css:
.loader {
  display: inline-block;
  width: 46px;
  height: 46px;
  border-radius: 50%;
  background: #6366f1;
  box-shadow: 0 0 0 0 rgba(99, 102, 241, 0.42);
  animation: glow 1.1s ease-in-out infinite;
}
@keyframes glow {
  0%, 100% { transform: scale(0.9); box-shadow: 0 0 0 0 rgba(99, 102, 241, 0.42); }
  50% { transform: scale(1); box-shadow: 0 0 0 18px rgba(99, 102, 241, 0); }
}
